sql:
SELECT MAX(pop_density) AS max_population_density
FROM pop_density
WHERE year = 2018;

SELECT distance
FROM distances
WHERE team_id = 1 AND event_id = 1;

SELECT SUM(amount) AS total_sponsorship
FROM team_sponsors
WHERE team_id = 1;

SELECT name, city, rookie_year
FROM teams
WHERE team_id = (SELECT MAX(team_id) FROM teams);
